Rules.InvariantScript:
// ══════════════════════════════════════════════════════════════════════
//  AGENDA — SERVIÇOS FINALIZADOS (OnVisible)
//  Betinhos Executive Service | 2026-03
// ══════════════════════════════════════════════════════════════════════

Set(varOrientacao, If(App.Width > App.Height, "Paisagem", "Retrato"));

Set(
    varMotoristaUser,
    LookUp(Funcionários, 'Email Microsoft' = User().Email)
);

If(
    varLoading || IsBlank(varMotoristaUser.'GUID Funcionários'),
    false,

    Set(varLoading, true);

    With(
        {
            dtFim:         DateAdd(Now(), 3, TimeUnit.Hours),
            dtInicio:      DateAdd(Now(), -5, TimeUnit.Days),
            guidMotorista: varMotoristaUser.'GUID Funcionários'
        },

        Clear(colAgendaServicosFinalizados);
        Clear(colFinalizadosServicos);
        Clear(colFinalizadosTrocas);
        Clear(colFinalizadosManut);
        Clear(colTrocasFinalizadasFiltradas);
        Clear(colGuidTrocasProgramadas);

        Concurrent(

            // 1) SERVIÇOS
            ClearCollect(
                colFinalizadosServicos,
                ForAll(
                    Filter(
                        Geral As G,
                        G.'Data e horário de saída' >= dtInicio &&
                        G.'Data e horário de saída' <  dtFim &&
                        G.Motorista.'GUID Funcionários' = guidMotorista &&
                        G.'Status de Operação' = 'Status de Operação'.Concluído &&
                        IsBlank(G.OM) &&
                        IsBlank(G.OT) &&
                        G.'Categoria do Item' = 'Categoria do Item'.Serviço
                    ) As S,
                    {
                        Tipo:                 "SERVICO",
                        DtOrdem:              S.'Data e horário de saída',
                        DataChave:            DateValue(Text(S.'Data e horário de saída', "[$-en-US]yyyy-mm-dd")),
                        DadosSERVICO:         S,
                        DadosTROCA:           Blank(),
                        DadosMANUTENCAO:      Blank(),
                        DadosMANUTENCAOGeral: Blank()
                    }
                )
            ),

            // 2) MANUTENÇÕES
            ClearCollect(
                colFinalizadosManut,
                ForAll(
                    Filter(
                        Geral As G,
                        G.'Data e horário de saída' >= dtInicio &&
                        G.'Data e horário de saída' <  dtFim &&
                        G.Motorista.'GUID Funcionários' = guidMotorista &&
                        !IsBlank(G.OM) &&
                        IsBlank(G.OT) &&
                        G.'Categoria do Item' = 'Categoria do Item'.Manutenção &&
                        G.OM.'Status (cr40f_status)' = 'Status (Manutenções)'.Realizado
                    ) As S,
                    {
                        Tipo:                 "MANUTENCAO",
                        DtOrdem:              S.'Data e horário de saída',
                        DataChave:            DateValue(Text(S.'Data e horário de saída', "[$-en-US]yyyy-mm-dd")),
                        DadosSERVICO:         Blank(),
                        DadosTROCA:           Blank(),
                        DadosMANUTENCAO:      S.OM,
                        DadosMANUTENCAOGeral: S
                    }
                )
            ),

            // 3a) TROCAS — pré-filtro
            ClearCollect(
                colTrocasFinalizadasFiltradas,
                Filter(
                    'Trocas de Carro' As T,
                    T.'Início da Janela de Troca' <= dtFim &&
                    T.'Fim da Janela de Troca'    >= dtInicio &&
                    (
                        T.'Motorista 1'.'GUID Funcionários' = guidMotorista ||
                        T.'Motorista 2'.'GUID Funcionários' = guidMotorista
                    ) &&
                    T.'Status (cr40f_statusdatroca)' = 'Status da Troca de Carro'.Concluída
                )
            ),

            // 3b) TROCAS — GUIDs programados (campo OT)
            ClearCollect(
                colGuidTrocasProgramadas,
                ForAll(
                    Filter(
                        Geral As G,
                        G.'Categoria do Item' = 'Categoria do Item'.'Troca de Veículos' &&
                        !IsBlank(G.OT)
                    ) As G,
                    { GuidOT: G.OT.'GUID Trocas de Carro' }
                )
            )

        ); // fim Concurrent

        // 3c) TROCAS — join local (sequencial, depende de 3a + 3b)
        ClearCollect(
            colFinalizadosTrocas,
            ForAll(
                Filter(
                    colTrocasFinalizadasFiltradas As T,
                    CountIf(
                        colGuidTrocasProgramadas,
                        GuidOT = T.'GUID Trocas de Carro'
                    ) > 0
                ) As T,
                {
                    Tipo:                 "TROCA",
                    DtOrdem:              T.'Início da Janela de Troca',
                    DataChave:            DateValue(Text(T.'Início da Janela de Troca', "[$-en-US]yyyy-mm-dd")),
                    DadosSERVICO:         Blank(),
                    DadosTROCA:           T,
                    DadosMANUTENCAO:      Blank(),
                    DadosMANUTENCAOGeral: Blank()
                }
            )
        );

        // ── DEBUG (descomente para validar) ───────────────────────────
        // Notify(
        //     "Serviços: "  & CountRows(colFinalizadosServicos) &
        //     " | Manut: "  & CountRows(colFinalizadosManut)    &
        //     " | Trocas: " & CountRows(colFinalizadosTrocas);
        //     NotificationType.Information; 6000
        // );;

        // ── CONSOLIDA ─────────────────────────────────────────────────
        With(
            {
                baseUnificada: SortByColumns(
                    AddColumns(
                        Ungroup(
                            Table(
                                { Value: colFinalizadosServicos },
                                { Value: colFinalizadosTrocas   },
                                { Value: colFinalizadosManut    }
                            ),
                            Value
                        ),
                        DtLocal,
                        Coalesce(DtOrdem, dtInicio)
                    ),
                    "DtLocal",
                    SortOrder.Descending
                )
            },

            ForAll(
                SortByColumns(
                    RenameColumns(
                        Distinct(
                            Filter(baseUnificada, !IsBlank(DataChave)),
                            DataChave
                        ),
                        Value,
                        DataChave
                    ),
                    "DataChave",
                    SortOrder.Descending
                ) As D,

                With(
                    { hoje: Today() },

                    Collect(
                        colAgendaServicosFinalizados,
                        {
                            Tipo:                 "HEADER",
                            DtOrdem:              DateTimeValue(Text(D.DataChave, "[$-en-US]yyyy-mm-dd") & " 00:00"),
                            DataChave:            D.DataChave,
                            TituloData:           "Serviços de " & Switch(
                                                      true,
                                                      D.DataChave = hoje,              "HOJE",
                                                      D.DataChave = DateAdd(hoje, -1), "ONTEM",
                                                      D.DataChave = DateAdd(hoje, -2), "2 dias atrás",
                                                      D.DataChave = DateAdd(hoje, -3), "3 dias atrás",
                                                      D.DataChave = DateAdd(hoje, -4), "4 dias atrás",
                                                      D.DataChave = DateAdd(hoje, -5), "5 dias atrás",
                                                      Text(D.DataChave, "[$-pt-BR]dddd, dd/mm/yyyy")
                                                  ),
                            DadosSERVICO:         Blank(),
                            DadosTROCA:           Blank(),
                            DadosMANUTENCAO:      Blank(),
                            DadosMANUTENCAOGeral: Blank()
                        }
                    );

                    ForAll(
                        SortByColumns(
                            Filter(baseUnificada, DataChave = D.DataChave),
                            "DtLocal",
                            SortOrder.Descending
                        ) As I,
                        Collect(
                            colAgendaServicosFinalizados,
                            {
                                Tipo:                 I.Tipo,
                                DtOrdem:              I.DtOrdem,
                                DataChave:            I.DataChave,
                                TituloData:           Blank(),
                                DadosSERVICO:         I.DadosSERVICO,
                                DadosTROCA:           I.DadosTROCA,
                                DadosMANUTENCAO:      I.DadosMANUTENCAO,
                                DadosMANUTENCAOGeral: I.DadosMANUTENCAOGeral
                            }
                        )
                    )
                )
            )
        );

        Set(varLoading, false);
        true
    )
)

ControlPropertyState.AutoRuleBindingString:
Set(
    varOrientacao,
    If(
        App.Width > App.Height,
        "Paisagem",
        "Retrato"
    )
);
If(
    varLoading,
    false,
    Set(
        varLoading,
        true
    );
    With(
        {
            dtInicioLocal: DateAdd(
                Now(),
                -1,
                TimeUnit.Hours
            ),
            dtFimLocal: DateAdd(
                Now(),
                24,
                TimeUnit.Hours
            ),
            guidMotorista: varMotoristaUser.'GUID Funcionários'
        },
        If(
            IsBlank(guidMotorista),
            false,
            // ZERA COLEÇÕES
            Clear(colAgendaServicos);
            Clear(colAgendaTrocas);
            Clear(colAgendaManut);
            Clear(colAgenda);
            Clear(colAgendaUI);
            // =========================
            // CARGAS PARALELAS INDEPENDENTES
            // =========================
            Concurrent(
                // SERVIÇOS
                ClearCollect(
                    colAgendaServicos,
                    ForAll(
                        Filter(
                            Geral As G,
                            G.'Data e horário de saída' >= dtInicioLocal && G.'Data e horário de saída' <= dtFimLocal && G.Motorista.'GUID Funcionários' = guidMotorista && G.'Status de Operação' <> 'Status de Operação'.Concluído && IsBlank(G.OM) && IsBlank(G.OT) && G.Programado = true && G.'Categoria do Item' = 'Categoria do Item'.Serviço
                        ) As S,
                        {
                            Tipo: "SERVICO",
                            DtOrdem: Coalesce(
                                S.'Data e horário de saída',
                                dtInicioLocal
                            ),
                            DadosSERVICO: S,
                            DadosTROCA: Blank(),
                            DadosMANUTENCAO: Blank(),
                            DadosMANUTENCAOGeral: Blank()
                        }
                    )
                ),
                // MANUTENÇÕES
                ClearCollect(
                    colAgendaManut,
                    ForAll(
                        Filter(
                            Geral As G,
                            G.'Data e horário de saída' >= dtInicioLocal && G.'Data e horário de saída' <= dtFimLocal && G.Motorista.'GUID Funcionários' = guidMotorista && !IsBlank(G.OM) && IsBlank(G.OT) && G.'Status de Operação' <> 'Status de Operação'.Concluído && G.Programado = true
                             && G.'Categoria do Item' = 'Categoria do Item'.Manutenção
                        ) As S,
                        If(
                            S.OM.'Status (cr40f_status)' = 'Status (Manutenções)'.Realizado,
                            Blank(),
                            {
                                Tipo: "MANUTENCAO",
                                DtOrdem: Coalesce(
                                    S.'Data e horário de saída',
                                    dtInicioLocal
                                ),
                                DadosSERVICO: Blank(),
                                DadosTROCA: Blank(),
                                DadosMANUTENCAO: S.OM,
                                DadosMANUTENCAOGeral: S
                            }
                        )
                    )
                ),
                // TROCAS — passo 1: trocas do motorista no período
                ClearCollect(
                    colTrocasFiltradas,
                    Filter(
                        'Trocas de Carro' As T,
                        T.'Início da Janela de Troca' <= dtFimLocal && T.'Fim da Janela de Troca' >= dtInicioLocal && (T.'Motorista 1'.'GUID Funcionários' = guidMotorista || T.'Motorista 2'.'GUID Funcionários' = guidMotorista) && T.'Status da Troca' <> 'Status da Troca de Carro'.Concluída
                    )
                ),
                // TROCAS — passo 2: GUIDs programados na Geral
                ClearCollect(
                    colGuidProgramados,
                    Filter(
                        Geral As G,

                        G.Programado = true && G.'Categoria do Item' = 'Categoria do Item'.'Troca de Veículos'
                    )
                )
            );
            // TROCAS — passo 3: join local (sem delegação, sem aviso)
            ClearCollect(
                colAgendaTrocas,
                ForAll(
                    Filter(
                        colTrocasFiltradas As T,
                        CountIf(
                            colGuidProgramados,
                            OT.'GUID Trocas de Carro' = T.'GUID Trocas de Carro'
                        ) > 0
                    ) As T,
                    {
                        Tipo: "TROCA",
                        DtOrdem: Coalesce(
                            T.'Início da Janela de Troca',
                            dtInicioLocal
                        ),
                        DadosSERVICO: Blank(),
                        DadosTROCA: T,
                        DadosMANUTENCAO: Blank(),
                        DadosMANUTENCAOGeral: Blank()
                    }
                )
            );
            // =========================
            // CONSOLIDA
            // =========================
            ClearCollect(
                colAgenda,
                colAgendaServicos,
                colAgendaTrocas,
                colAgendaManut
            );
            // =========================
            // NORMALIZA PARA UI
            // =========================
            With(
                {
                    baseLocal: SortByColumns(
                        AddColumns(
                            colAgenda As A,
                            DtLocal,
                            Coalesce(
                                A.DtOrdem,
                                dtInicioLocal
                            ),
                            DataChave,
                            DateValue(
                                Coalesce(
                                    A.DtOrdem,
                                    dtInicioLocal
                                )
                            )
                        ),
                        "DtLocal",
                        SortOrder.Ascending
                    )
                },
                ForAll(
                    SortByColumns(
                        RenameColumns(
                            Distinct(
                                baseLocal,
                                DataChave
                            ),
                            Value,
                            DataChave
                        ),
                        "DataChave",
                        SortOrder.Ascending
                    ) As D,
                    With(
                        {t: Today()},
                        Collect(
                            colAgendaUI,
                            {
                                Tipo: "HEADER",
                                DtLocal: DateTimeValue(
                                    Text(
                                        D.DataChave,
                                        "[$-en-US]yyyy-mm-dd"
                                    ) & " 00:00"
                                ),
                                DtOrdem: DateTimeValue(
                                    Text(
                                        D.DataChave,
                                        "[$-en-US]yyyy-mm-dd"
                                    ) & " 00:00"
                                ),
                                DataChave: D.DataChave,
                                TituloData: "Serviços de " & If(
                                    D.DataChave = t,
                                    "HOJE",
                                    D.DataChave = DateAdd(
                                        t,
                                        1
                                    ),
                                    "AMANHÃ",
                                    D.DataChave = DateAdd(
                                        t,
                                        -1
                                    ),
                                    "ONTEM",
                                    Text(
                                        D.DataChave,
                                        "[$-pt-BR]dddd, dd/mm/yyyy"
                                    )
                                ),
                                Seta: "▾",
                                DadosSERVICO: Blank(),
                                DadosTROCA: Blank(),
                                DadosMANUTENCAO: Blank(),
                                DadosMANUTENCAOGeral: Blank()
                            }
                        );
                        ForAll(
                            Filter(
                                baseLocal,
                                DataChave = D.DataChave
                            ) As I,
                            Collect(
                                colAgendaUI,
                                {
                                    Tipo: I.Tipo,
                                    DtLocal: I.DtLocal,
                                    DtOrdem: I.DtOrdem,
                                    DataChave: I.DataChave,
                                    TituloData: Blank(),
                                    Seta: Blank(),
                                    DadosSERVICO: I.DadosSERVICO,
                                    DadosTROCA: I.DadosTROCA,
                                    DadosMANUTENCAO: I.DadosMANUTENCAO,
                                    DadosMANUTENCAOGeral: I.DadosMANUTENCAOGeral
                                }
                            )
                        )
                    )
                )
            );
            Set(
                varLoading,
                false
            );
            true
        )
    )
)

